// This script runs when the window opens
let counter = 0;

// Button to read clipboard using workflow tool
document.getElementById('btn-clipboard').addEventListener('click', async () => {
  const result = await stuard.callTool('get_clipboard_content');
  const el = document.getElementById('clipboard-result');
  if (result.ok) {
    el.textContent = 'Clipboard: ' + (result.text || '(empty)').slice(0, 50);
  } else {
    el.textContent = 'Error: ' + result.error;
  }
});

// Counter increment button
document.getElementById('btn-increment').addEventListener('click', () => {
  counter++;
  document.getElementById('counter').textContent = counter;
  formData.counter = counter;
});

// Notification button
document.getElementById('btn-notify').addEventListener('click', () => {
  stuard.notify('Hello from Custom UI!', 'This notification was triggered from JavaScript');
});

// Copy to clipboard button
document.getElementById('btn-copy').addEventListener('click', async () => {
  await stuard.copyToClipboard('Hello from StuardAI Custom UI!');
  stuard.notify('Copied!', 'Text copied to clipboard');
});

console.log('[Demo] Custom UI initialized with stuard API:', typeof stuard);
